export interface ConcourAM {
  id: number;
  date: string;          // ISO YYYY-MM-DD
  dateFin?: string;      // si multi-jours
  ville: string;
  club: string;
  intitule: string;      // Nom exact du concours
  categorie: string;     // Sénior / Vétéran / Féminin / Mixte / Jeunes / Jeu Provençal / Entreprises / NC-Promotion
  niveau: string;        // National / Régional / Départemental / Qualificatif / Promotion / International
  format: string;        // Tx3 / Dx2 / Dx3 / Vx2 / Vx3 etc.
  horaire?: string;      // "14h00" etc.
  limite?: number;       // limite d'équipes
  dotation?: string;     // "4500€" etc.
  info?: string;         // infos complémentaires
  lat: number;
  lng: number;
  type: "CONCOURS" | "CHAMPIONNAT" | "RÉGIONAL" | "NATIONAL" | "INTERNATIONAL" | "SPÉCIAL";
}

