// ── Utilitaires ────────────────────────────────────────────────────────────

export function getAMByMonth(month: number, year: number): ConcourAM[] {
  return CONCOURS_AM_2026.filter(c => {
    const d = new Date(c.date);
    return d.getMonth() + 1 === month && d.getFullYear() === year;
  });
}

export function getAMByNiveau(niveau: string): ConcourAM[] {
  return CONCOURS_AM_2026.filter(c => c.niveau === niveau);
}

export function getAMByCategorie(categorie: string): ConcourAM[] {
  return CONCOURS_AM_2026.filter(c =>
    c.categorie.toLowerCase().includes(categorie.toLowerCase())
  );
}
